/* Linker version script for libc4a.so on Linux.
 *
 * Limits the exported symbol set to `c4a_*` (the documented public C ABI).
 * Combined with -fvisibility=hidden (set globally in CMakeLists.txt), this
 * gives defense-in-depth against accidentally exposing internal helpers.
 *
 * This file is picked up automatically by cpp/src/CMakeLists.txt when it
 * exists. The active CHEMOMETRICS4ALL_<VERSION> tag bumps with the ABI
 * major version.
 */

CHEMOMETRICS4ALL_1 {
    global:
        c4a_*;
    local:
        *;
};
